"use client"

import {useState} from "react"
import { Drawer } from "vaul";

export default function FamilyDrawer() {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <button
         className="focus-visible:shadow-focus-ring-button fixed top-1/2 left-1/2 h-[44px] -translate-x-1/2 -translate-y-1/2 rounded-full border border-gray-200 bg-white px-6 py-2 font-medium text-black transition-colors hover:bg-[#F9F9F8] md:font-medium"

        >
            Try it out
        </button>
    )
}
